#include <stdio.h>
#include <stdlib.h>

#define INDEX_SIZE 100
#define RECORD_SIZE 200

typedef struct {
    int key;
    int fileOffset;
} IndexEntry;

// Binary search on index
int searchIndex(IndexEntry index[], int size, int searchKey) {
    int left = 0, right = size - 1;

    while (left <= right) {
        int mid = (left + right) / 2;

        if (index[mid].key == searchKey)
            return index[mid].fileOffset;
        else if (index[mid].key < searchKey)
            left = mid + 1;
        else
            right = mid - 1;
    }
    return -1;  // Not found
}

// Read record from data file using offset
void* readRecordAtOffset(FILE* dataFile, int offset) {
    void* record = malloc(RECORD_SIZE);

    fseek(dataFile, offset, SEEK_SET);
    fread(record, RECORD_SIZE, 1, dataFile);

    return record;
}

// Main indexed search function
void* indexedSearch(FILE* indexFile, FILE* dataFile, int searchKey) {
    IndexEntry index[INDEX_SIZE];

    // Load index into memory
    fread(index, sizeof(IndexEntry), INDEX_SIZE, indexFile);

    // Search index - O(log n)
    int offset = searchIndex(index, INDEX_SIZE, searchKey);

    if (offset == -1)
        return NULL;

    // Read actual record - O(1)
    return readRecordAtOffset(dataFile, offset);
}

import java.io.*;

class BufferedFileReader {
    private FileInputStream fis;
    private BufferedInputStream buffer;
    private final int BUFFER_SIZE = 8192;  // 8KB buffer

    public BufferedFileReader(String filename) throws IOException {
        fis = new FileInputStream(filename);
        buffer = new BufferedInputStream(fis, BUFFER_SIZE);
    }

    public int read() throws IOException {
        return buffer.read();  // Reads from buffer, not disk
    }

    public byte[] readBlock(int size) throws IOException {
        byte[] data = new byte[size];
        int bytesRead = buffer.read(data);

        if (bytesRead == -1) return null;

        if (bytesRead < size) {
            byte[] trimmed = new byte[bytesRead];
            System.arraycopy(data, 0, trimmed, 0, bytesRead);
            return trimmed;
        }
        return data;
    }

    public void close() throws IOException {
        buffer.close();
        fis.close();
    }
}

class BufferManager {
    // Simulated buffer pool
    private static final int NUM_BUFFERS = 10;
    private byte[][] bufferPool = new byte[NUM_BUFFERS][4096];
    private boolean[] dirtyFlags = new boolean[NUM_BUFFERS];
    private int[] accessCount = new int[NUM_BUFFERS];

    // Least Recently Used (LRU) replacement
    public int getFreeBuffer() {
        for (int i = 0; i < NUM_BUFFERS; i++) {
            if (accessCount[i] == 0) return i;
        }

        // Find LRU buffer and flush if dirty
        int lru = 0;
        int minCount = accessCount[0];
        for (int i = 1; i < NUM_BUFFERS; i++) {
            if (accessCount[i] < minCount) {
                minCount = accessCount[i];
                lru = i;
            }
        }

        if (dirtyFlags[lru]) {
            flushBuffer(lru);  // Write back to disk
        }

        return lru;
    }

    private void flushBuffer(int bufferId) {
        // Write buffer content to disk
        System.out.println("Flushing buffer " + bufferId + " to disk");
        dirtyFlags[bufferId] = false;
    }

    public void markDirty(int bufferId) {
        dirtyFlags[bufferId] = true;
    }

    public void accessBuffer(int bufferId) {
        accessCount[bufferId]++;
    }
}
